INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-006', 'Red Hat T-shirt', 'Interior custom branding options. Tearaway-cutaway main label for tagless comfort. Tubular knit. Crew neck. Flat knit collar. Self fabric necktape. Single Jersey knit of 100% Cotton, 150 g/m2. Colour: Black', 1, 11.25);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-018', 'We Are Red Hat Week T-Shirt', 'Interior custom branding options. Tearaway-cutaway main label for tagless comfort. Tubular knit. Crew neck. Flat knit collar. Self fabric necktape. Single Jersey knit of 100% Cotton, 150 g/m2. Colour: Black', 1, 13.50);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-007', 'Red Hat Recycled Polo', 'Short sleeve men''s GOTS organic GRS recycled polo. Sustainable promotional apparel. Sustainable metal buttons. Flat knit collar. Flat knit rib cuffs. Two button placket. Bi-coloured necktape. Double needle stitching detail. Material: Piqué knit of 70% GOTS certified organic cotton and 30% GRS certified recycled polyester, 220 g/m2. Colour: Black', 1, 29.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-017', 'We Are Red Hat Week Sweatshirt', 'Interior custom branding options. Tearaway-cutaway main label for tagless comfort. Crew neck. Flat knit rib collar. Flat knit rib cuffs. Flat knit rib bottom hem. Brushed on the inside. Self-fabric necktape. Knit of 50% Cotton and 50% Polyester, 240 g/m2.', 1, 26.95);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-009', 'Red Hat Full Zipped Hoodie - Unisex', 'Unisex full zip hoodie with contrast plastic zip. Twin needle stitching detailing. Double fabric hood with contrast inner. Contrast flat lace drawcords. Kangaroo pouch pocket. Ribbed cuff and hem. Worldwide Responsible Accredited Production (WRAP) certified production. Soft cotton faced fabric creates ideal printing surface. Simple tear out label makes it perefct for rebranding. Brushed inner fleece. Branded with Equinix logo. Fabric : 80% Ringspun cotton, 20% Polyester; Weight: 280gsm, Colour:Black/Red', 1, 27.50);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-011', 'Red Hat Cooler Duffle Bag', 'Easy-access 24-can cooler bag. Zippered main compartment holds up to 24 cans. Zippered front compartment. Easy-access pocket allow for quick retrieval of chilled items. Backsaver™ technology combats the strain of carrying a loaded cooler. Ultra Safe™ leak-proof PEVA lining. Collapses for easy storage. 600D Polyester. Material: 420D of Polyester. Colour:Black/Red Product size (cm):30 x 23 x 29', 3, 38.50);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-002', 'Red Hat Ceramic Mug', 'Mug is 340 ml with matte exterior finish and interior colour accent. Dishwasher safe. Material: Ceramic. Capacity: 340ml Color: Black/Red Height: 8,40 cm Diameter:8,80 cm Weight:310 gram', 2, 6.95);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-004', 'Red Hat Black Tumbler', 'Vacuum insulated tumbler and insulator with 330 ml capacity. Double-wall construction, vacuum insulated. Clear, press-on lid with slide closure. Works as a tumbler or drink insulator. Material: Stainless Steel. Colour: Black. Height:13,50 cm Diameter:8,50 cm Weight:235 gram', 2, 12.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-016', 'Red Hat White Tumbler', 'Vacuum insulated tumbler and insulator with 330 ml capacity. Double-wall construction, vacuum insulated. Clear, press-on lid with slide closure. Works as a tumbler or drink insulator. Material: Stainless Steel. Colour: White', 2, 12.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-005', 'Red Hat Sport Bottle', 'Copper vacuum insulated sport bottle with 650 ml capacity. Durable, double wall stainless steel vacuum construction with copper insulation, which allows your beverage to stay cold for 48 hours and at least 12 hours for hot beverages. The construction also prevents condensation on the outside of the bottle. Material: Stainless Steel. Colour: Black Height:27,20 cm Diameter:7,20 cm Weight:380 gram', 2, 17.25);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-008', 'Red Hat Selfie Light', 'The Webcam Ring Light guarantees perfect lighting for all of your photos. Just clip it onto the top of your phone or laptop, press the on/off button at the bottom, and watch as the ring lights up. You can adjust the brightness of the light to three different levels. This also works great for creating the perfect lighting for a zoom meeting when working from home.', 4, 8.95);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNL-015', 'Red Hat Recycled Facemask', 'Two-layered face mask. Add-in filter pocket (filter not included). Metal nose bridge. Elastic straps with adjustable stopper. Ergonomic shape to protect mouth and chin. Washable at 60 degrees. Made of lightweight and comfortable 94% certified recycled polyester and 6% elastane. Colour:Solid black', 5, 4.30);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-257', '3/4" Fedora Lapel Pin', '3/4" silver plated metal lapel pin.', 5, 1.35);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-023E-RED', '6 Panel Unstructured Cap With Tuck Strap', 'Comfortable 6 panel unstructured cap with tuck strap fits sleek to your head. Garment Washed Cotton Twill Unstructured. Tuck Strap with Slide Closure. Color: Red with Red Hat logo embroidered in white on front of cap.', 1, 5.85);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-234', 'Women''s Red Hat Black T-Shirt', 'Women''s CVC Tee. 4.3-ounce, 60/40 combed ring spun cotton/poly. 32 singles. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side seamed. Fitted.', 1, 11.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-233', 'Red Hat Black T-Shirt', 'Unisex CVC Tee. 4.3-ounce, 60/40 combed ring-spun cotton/poly, 32 singles. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side-seamed', 1, 10.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-231', 'Red Hat Fedora Cap Heather Grey T-Shirt', '4.3-ounce Unisex 90/10 combed ring spun cotton/poly, 32 singles. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side seamed.', 1, 11.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-232', 'Women''s Red Hat Fedora Cap Heather Grey T-Shirt', 'Comfortable 6 panel unstructured cap with tuck strap fits sleek to your head. Garment Washed Cotton Twill Unstructured. Tuck Strap with Slide Closure. Color: Red with Red Hat logo embroidered in white on front of cap.', 1, 11.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-465', 'WARHW Black T-Shirt', '4.3-ounce, 60/40 combed ring spun cotton/poly, 32 singles. CVC blend. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side seamed.', 1, 11.85);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-255', 'Red Hat Linux Lining T-Shirt', '4.2 oz.(US) 7 oz.(CA), 100% airlume combed and ringspun cotton, 32 singles. Retail fit. Unisex sizing. Coverstitched collar and sleeves. Shoulder-to-shoulder taping. Side seams. Tear-away label. Color: Black', 1, 12.50);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-179', 'Red Hat Fedora Cap Heather Grey T-Shirt', '4.3-ounce Unisex 90/10 combed ring spun cotton/poly, 32 singles. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side seamed.', 1, 11.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-222', 'My Code Is Open Black T-Shirt', 'Unisex Tri-Blend Tee. 4.3-ounce, 50/25/25 poly/combed ring spun cotton/rayon, 30 singles. 1x1 rib knit neck. Shoulder to shoulder taping. Tear-away label. Side seamed.', 1, 14.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-245', 'Red Hat Recycled PET Plastic Pen', 'This gel pen is one of the new eco-friendly items in the Eco-Minded product line. The barrel and cap of this translucent pen are made with 100% post-consumer recycled P.E.T. plastic. Black Ink / Gel ink, 0.7 mm point- Cap-Off.', 4, 0.90);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-249', 'Red Hat 3/4" Recycled PET Dye-Sublimated Lanyard', '3/4" Recycled PET Dye-Sublimated w/Crimp, Split Ring & Black Metal Bulldog Clip W/ Swivel', 4, 2.75);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-094-WHT', 'Rechargeable Adjustable LED Webcam Ring Light', 'The Webcam Ring Light guarantees perfect lighting for all of your photos. Just clip it onto the top of your phone or laptop, press the on/off button at the bottom, and watch as the ring lights up. You can adjust the brightness of the light to three different levels. This also works great for creating the perfect lighting for a zoom meeting when working from home.', 4, 6.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-042E', 'Keychain Tool White', 'Keychain Tool White', 5, 5.75);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-239', 'Neoskin Hard Cover Journal', 'This hard-cover journal features a gusseted interior pocket to store your important business materials; 192 ivory-lined, acid free pages for your pen to glide on; a ribbon to double as a bookmark and an elastic closure to mark the next blank page. Product dimensions: (5.750"" x 8.375""). Journal inner page dimension is 5 1/2" x 8 3/16"', 4, 11.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-250', 'Red Hat Matte Black Camper Mug', '12 oz double wall 18/8 stainless steel thermal mug with copper vacuum insulation, stainless steel rim, clear push-on lid, swivel closure, and powder coated finish; Hand wash recommended; Do not microwave; 4"" h x 4-3/4 w (with handle).', 2, 16.99);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-095-RED', 'Desk Gift Set', '"You''re an overachiever and you don''t believe in cutting corners. When it comes to your workspace, it''s obvious that you''re gonna need the whole kit and caboodle. The set comes in a white box with all of your favorite desk items. Items included:  Pen Cup, Stapler, Tape Dispenser, Tray and (3) pens in White, Black and Red.', 4, 26.50);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-240', 'Stojo Collapsible Silicone Bottle - 20 oz.', 'Collapsible 20 oz Stojo bottle. Holds 20 ounces of liquid when full and collapses into a sphere when empty (3.3"" high). The tethered screw-on cap creates a loop handle and can be attached to your bag strap or belt. When screwed on tightly, the cap creates an air-tight, leak-proof seal. Color: Cashmere.', 2, 20.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-054E-RED', 'Fedora Shaped Earrings', 'Fedora Shaped Earrings', 5, 46.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-252-BLK', 'JBL Live 460 Wireless NC Headphone', 'Feel the power of JBL Signature Sound delivered by 40mm drivers, enjoy the convenience of Adaptive Noise Cancelling and Smart Ambient technologies that allow you to focus on what matters for you, and talk to your favorite Voice Assistant with a tap on the ear cup. Dimensions: 9 x 8 x 2.2.', 6, 129.95);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('RHNAM-219-BLKGRY', 'Two-Tone Double-Layer Yoga Mat', 'This two-tone double-layer yoga mat offers excellent traction and is hypoallergenic, non-toxic and odor-free. Made of closed-cell themorplastic elastomer. Mat size: 24 1/8" W x 71" L', 7, 25.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('101808', 'Vic Firth 5A American Classic Hickory', 'Size 5A - American Classic Series - Hickory wood - Wooden tips - Teardrop tips - Ideal for rock and as practice sticks - Length: 406 mm - Diameter: 14,4 mm', 8, 13.90);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('144011', 'Millenium 5A Maple Drumsticks', 'Material: Maple wood - With wooden tips - Length: 402 mm - Tip length: 13 mm - Body: 14,9 mm - Shoulder: 6 mm - Price for pair', 8, 2.25);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('459639', 'Kuppmen 5A Carbon Fiber Sticks', 'Strength: 5A - Material: Carbon - Identical weight to wooden sticks - Non-slip surface - Up to 10 times more durable than wooden sticks - Quantity: 1 Pair', 8, 29.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('101793', 'Vater 5A Los Angeles Sticks Wood','Size: 5A - American hickory wood - Wooden tips - Los Angeles - Length: 40.65 cm - Diameter: 14.5 mm - Very well balanced stick, heavier toward the tip for fast response - Good rebound from the drum', 8, 12.80);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('101759', 'Pro Mark TX5AW 5A Hickory - Wood Tip', 'Size: 5A - Hickory wood - Wooden tips - The quintessential drumstick - Suitable for all music styles - Length: 40.64 cm', 8, 13.90);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('328580', 'Gretsch Drums Catalina Club Jazz', 'Shell Set - Catalina Club Series - Jazz set - 7-Ply, 100% mahogany shells - Matt lacquered - 30 degrees bearing edge on all shells - GTS free-swinging Tom suspension mount - 1.6 mm hoops - Colour: Satin Walnut Glaze (SWG) - Set configuration: 18" x 14" Bass drum - 12" x 08" Tom Tom - 14" x 14" Floor tom - 14" x 5.5" Snare drum - Set includes Tom holder', 9, 739.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('422807', 'Sonor AQ2 Bop Set WHP', 'Drum shell pack - Shell material: 7-Ply maple shell - Shell hardware: Chrome - Includes tom holder - New SmartMount tom holder system for balanced, optimal sustain with smaller hardware footprint - Colour: White Pearl (foil) - Shell pack consisting of: 18" x 14" Bass drum - 12" x 08" Tom tom - 14" x 13" Floor tom - 14" x 06" Wooden snare drum', 9, 1049.00);
INSERT INTO catalog (item_id, name, description, category, price) VALUES ('433140', 'Yamaha Stage Custom Bop Kit NW', 'Shell set - Stage Custom Series - 6-Ply birch wood shells - High gloss lacquered - Chrome hardware - Y.E.S.S. tom holder system - Absolute tension rods - Steel hoops - Newly designed bass drum feet - Colour: Natural Wood - Shell set consisting of: 18" x 15" bass drum (drilled) - 12" x 08" Tom Tom - 14" x 13" Stand Tom - Includes single tom holder', 9, 698.00);
